INSERT INTO `posts` (`z_user_id`, `language`, `title`, `subtitle`, `content`, `is_published`, `published_at`, `created_at`, `updated_at`) VALUES
-- Januar bis März (jeweils 1)
(1, 'de', 'Kalter Januar auf dem Bike', 'Die Saison beginnt früh', '[b]Saisonstart 2023![/b] Es war [i]verdammt kalt[/i], aber das Gefühl, wieder im Sattel zu sitzen, ist unbeschreiblich. [list][*]Griffheizung auf Stufe 3[*]Thermo-Unterwäsche[*]Heißer Kaffee an der Tanke[/list] Ein gelungener Tag!', 1, '2023-01-15 10:00:00', '2023-01-15 10:00:00', '2023-01-15 10:00:00'),
(1, 'de', 'Februar-Blues', NULL, '[b]Warten auf den Frühling.[/b] Das Motorrad steht noch in der Garage. Ich habe heute nur [u]die Kette gereinigt[/u] und die Batterie gecheckt. [url=https://example.com/pflege]Meine Pflegetipps[/url].', 1, '2023-02-20 14:00:00', '2023-02-20 14:00:00', '2023-02-20 14:00:00'),
(1, 'de', 'Erste Frühlingsboten', 'März-Tour', '[b]Endlich zweistellige Plusgrade![/b] Die Straßen werden trockener. [list=1][*]Reifendruck prüfen[*]Ölstand checken[*]Losfahren[/list] Der Grip ist noch mäßig, aber es macht wieder richtig Laune.', 1, '2023-03-10 11:30:00', '2023-03-10 11:30:00', '2023-03-10 11:30:00'),

