INSERT INTO `posts` (`z_user_id`, `language`, `title`, `subtitle`, `content`, `is_published`, `published_at`, `created_at`, `updated_at`) VALUES
(1, 'de', 'Der perfekte Saisonstart', 'Technik-Check und erste Tour', '[b]Es ist wieder soweit![/b] Die ersten Sonnenstrahlen brechen durch die Wolkendecke und die Temperaturen klettern endlich wieder in den zweistelligen Bereich. Das bedeutet für uns Motorradfahrer nur eins: Die Saison ist offiziell eröffnet! 

[b]Vorbereitung ist alles:[/b] Bevor man sich aber blindlings auf die Maschine schwingt, sollte man unbedingt einen gründlichen Technik-Check durchführen. 
[list]
[*]Reifendruck kontrollieren, da dieser über den Winter oft absinkt.
[*]Flüssigkeiten wie Öl, Bremsflüssigkeit und Kühlwasser penibel prüfen.
[*]Kette reinigen, auf Spannung prüfen und neu fetten.
[/list] 

Wenn das alles erledigt ist, steht der ersten großen Ausfahrt absolut nichts mehr im Weg. Ich habe heute direkt eine 250 Kilometer Tour durch das kurvige Hinterland gemacht. Der Asphalt war in schattigen Waldstücken stellenweise noch etwas rutschig und feucht, aber das Gefühl der Freiheit ist einfach unbezahlbar. [i]Passt auf euch auf und fahrt am Anfang der Saison immer mit einer extra Portion Vorsicht![/i]', 1, '2024-03-15 10:00:00', '2024-03-15 10:00:00', '2024-03-15 10:00:00'),

(1, 'de', 'Gepäcksysteme im Härtetest', 'Koffer, Rolle oder Tankrucksack?', '[b]Die ewige Frage vor dem Motorradurlaub:[/b] Wie bekomme ich mein ganzes Zeug auf die Maschine, ohne dass das Fahrverhalten komplett ruiniert wird? Ich habe in den letzten Jahren wirklich alles durchprobiert und möchte meine Erfahrungen mit euch teilen. 

Ein [u]Tankrucksack[/u] ist für mich absolute Pflicht. Hier kommen die schweren Dinge rein (Werkzeug, Wasser, Kamera), um den Schwerpunkt zentral und tief zu halten. Das Vorderrad behält so seinen Grip. 
Am Heck scheiden sich die Geister. [b]Alukoffer[/b] sind super praktisch, wasserdicht und diebstahlsicher. Allerdings bauen sie enorm breit, was das Durchschlängeln im Stau (natürlich nur da, wo es legal ist!) extrem erschwert. Außerdem verändern sie bei hohem Tempo die Aerodynamik spürbar. 
Meine aktuelle Lieblingslösung ist eine robuste [b]Gepäckrolle (Drybag)[/b] längs auf dem Soziussitz, kombiniert mit weichen Satteltaschen. Das spart Gewicht, ist flexibel und zwingt einen dazu, wirklich nur das Nötigste einzupacken. [i]Was sind eure bevorzugten Setups für die große Tour?[/i]', 1, '2024-07-20 14:30:00', '2024-07-20 14:30:00', '2024-07-20 14:30:00'),

(2, 'en', 'Mastering the Trackday', 'My first time dragging knee', '[b]What an absolute adrenaline rush![/b] I just got back from my very first official trackday and I am completely exhausted but happier than ever. Riding on a closed circuit without having to worry about oncoming traffic, speed limits, or gravel on the road is a completely different world.

The first two sessions were mostly about learning the layout of the track and finding my braking markers. I was definitely braking way too early and coasting into the corners. But thanks to one of the instructors who let me follow his lines, everything started to click in the afternoon. 
[list=1]
[*]Look through the corner, not at the apex.
[*]Be smooth on the throttle roll-on.
[*]Trust your tires! The grip level of a warm sport tire on race tarmac is mind-blowing.
[/list]
By the end of the day, I finally managed to get my knee down consistently in the long sweepers. It is an amazing feeling of bike control. [u]I am officially addicted[/u] and already looking for the next available dates. Highly recommend everyone to try it at least once!', 1, '2025-06-10 18:00:00', '2025-06-10 18:00:00', '2025-06-10 18:00:00'),

(2, 'de', 'Entwurf: Fahrwerks-Setup', 'Zug- und Druckstufe verstehen', '[b]Das größte Geheimnis für mehr Speed und Sicherheit:[/b] Ein richtig eingestelltes Fahrwerk! Viele Fahrer geben tausende Euro für laute Auspuffanlagen oder Carbon-Teile aus, fahren aber mit dem werksseitigen Standard-Setup durch die Gegend, das oft für einen 75kg Durchschnittsfahrer berechnet wurde.

Ich habe mich dieses Wochenende intensiv mit meinem Federbein und der Gabel beschäftigt. Der wichtigste erste Schritt ist das Einstellen des [i]Negativfederwegs (Sag)[/i]. Wenn die Basis nicht stimmt, nützt das Drehen an den Schräubchen für Zug- und Druckstufe überhaupt nichts. 
[u]Notizen für später:[/u] Ich muss den Text noch mit genauen Messwerten ergänzen. Die Gabel taucht beim harten Ankern immer noch etwas zu schnell ab. Werde die Druckstufe (Compression) vorne um 2 Klicks schließen und testen, ob das Feedback vom Vorderreifen dadurch besser wird. Bilder von den Einstellschrauben muss ich morgen noch bei Tageslicht machen.', 0, NULL, '2025-09-05 11:15:00', '2025-09-05 11:15:00'),

(1, 'de', 'Die Kunst des Kurvenfahrens', 'Blickführung ist alles', '[b]Die Landstraße ist kein Rennkurs[/b], aber flüssiges und sicheres Kurvenfahren macht genau dort den meisten Spaß. Nach über 10 Jahren im Sattel fällt mir immer wieder auf, dass der häufigste Fehler bei Anfängern (und auch vielen Fortgeschrittenen) eine schlechte Blickführung ist. 

[i]"Du fährst dorthin, wo du hinschaust."[/i] Dieser alte Fahrlehrer-Spruch ist ein physikalisches Gesetz auf dem Motorrad. Wenn du in einer Kurve panisch auf den Graben oder das entgegenkommende Auto starrst, wird dein Gehirn deine Hände genau in diese Richtung lenken. 
[list]
[*]Kopf aktiv in die Kurve drehen.
[*]Den Kurvenausgang fokussieren, nicht das Vorderrad.
[*]Linienwahl: Außen anfahren, spät einlenken, erst am Scheitelpunkt ans Gas gehen.
[/list]
Besonders bei blinden Kurven ist die späte Einlenk-Taktik überlebenswichtig, da man so viel mehr Sichtweite in den Kurvenverlauf bekommt. [u]Übung macht den Meister:[/u] Versucht bei der nächsten Fahrt ganz bewusst euren Blick zu scannen. Es fühlt sich anfangs vielleicht übertrieben an, den Kopf so stark zu drehen, aber das Motorrad folgt fast wie von Zauberhand.', 1, '2026-04-12 09:45:00', '2026-04-12 09:45:00', '2026-04-12 09:45:00');